sql:
SELECT data_type, AVG(bits) AS avg_bits
FROM configurations
GROUP BY data_type;

SELECT config_name
FROM configurations
WHERE bits = 0 AND config_name = 'External pin reset disable';

SELECT config_id, description
FROM configurations
WHERE default_value = (SELECT MAX(default_value) FROM configurations);

